/**
 * @summary Get current user's connection state for a list of clerk IDs
 */
export const getGetConnectionStatusUrl = (
  params: GetConnectionStatusParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/users/me/connection-status?${stringifiedParams}`
    : `/api/users/me/connection-status`;
};

export const getConnectionStatus = async (
  params: GetConnectionStatusParams,
  options?: RequestInit,
): Promise<ConnectionStatusResponse> => {
  return customFetch<ConnectionStatusResponse>(
    getGetConnectionStatusUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getGetConnectionStatusQueryKey = (
  params?: GetConnectionStatusParams,
) => {
  return [
    `/api/users/me/connection-status`,
    ...(params ? [params] : []),
  ] as const;
};

