/**
 * @summary Check whether a username is available
 */
export const getCheckUsernameAvailableUrl = (
  params: CheckUsernameAvailableParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/users/username-available?${stringifiedParams}`
    : `/api/users/username-available`;
};

export const checkUsernameAvailable = async (
  params: CheckUsernameAvailableParams,
  options?: RequestInit,
): Promise<UsernameAvailability> => {
  return customFetch<UsernameAvailability>(
    getCheckUsernameAvailableUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

