/**
 * Entity-scoped messaging. Every approved member sees the same
thread; the caller must have an active (`archivedAt IS NULL`)
`entity_members` row with `status='approved'`. Reading a
thread also clears the caller's unread rows for that entity.

 * @summary List the entity's shared message thread
 */
export const getListEntityMessagesUrl = (
  entityId: number,
  params?: ListEntityMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/entities/${entityId}/messages?${stringifiedParams}`
    : `/api/entities/${entityId}/messages`;
};

